const results = [];

const gmailItems = $("Gmail Trigger").all();

for (const item of gmailItems) {
  const text = item.json.text || "";

  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const urls = text.match(urlRegex) || [];

  results.push({
    json: {
      extractedUrls: urls,
      firstUrl: urls.length > 0 ? urls[0] : null,
      driveData: $input.item.json
    }
  });
}

return results;

